import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    public static void main (String[] args) throws java.lang.Exception {
        Scanner sc = new Scanner(System.in);

        // Read number of trains
        int n = sc.nextInt();

        // Create arrays to hold arrival and departure times
        int[] arr = new int[n];
        int[] dep = new int[n];

        // Read arrival times and calculate departure times
        for (int i = 0; i < n; i++) {
            arr[i] = sc.nextInt(); // Arrival time
            int stoppage = sc.nextInt(); // Stoppage time
            dep[i] = arr[i] + stoppage; // Calculate departure time
        }

        // Sort arrival and departure times
        Arrays.sort(arr);
        Arrays.sort(dep);

        // Initialize pointers and platform counters
        int i = 1, j = 0, currPlatforms = 1, ans = 1;

        // Loop through arrival and departure arrays
        while (i < n && j < n) {
            // If next train arrives before the last one departs
            if (arr[i] <= dep[j]) {
                currPlatforms++; // Increase platform count
                ans = Math.max(ans, currPlatforms); // Update maximum platforms needed
                i++; // Move to next train
            } else {
                currPlatforms--; // Train departs, decrease platform count
                j++; // Move to next departure
            }
        }

        // Output the result
        System.out.println(ans);
    }
}

