const readline = require('readline');

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

const input = [];

rl.on('line', line => {
    input.push(line);
});

rl.on('close', () => {
    // Parse the number of elements
    const n = parseInt(input[0]);
    const a = [];
    const b = [];

    // Read input pairs and modify array b based on a + b
    for (let i = 1; i <= n; i++) {
        let [ai, bi] = input[i].split(' ').map(Number);
        a.push(ai);
        b.push(ai + bi);
    }

    // Sort both arrays
    a.sort((x, y) => x - y);
    b.sort((x, y) => x - y);

    let p = 1, r = 1;
    let i = 1, j = 0;

    // Process the arrays
    while (i < n && j < n) {
        if (a[i] <= b[j]) {
            p++;
            i++;
        } else {
            p--;
            j++;
        }
        if (p > r) {
            r = p;
        }
    }

    // Output the result
    console.log(r);
});
